@Composable
fun ProfileCard(name: String, email: String, onFollow: () -> Unit) {
    Column(
        modifier = Modifier.padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        Text(
            text = name,
            fontSize = 20.sp,
            fontWeight = FontWeight.Bold
        )
        Text(
            text = email,
            fontSize = 14.sp,
            color = Color.Gray
        )
        Button(onClick = onFollow) {
            Text("Follow")
        }
    }
}

